{
  "title": "Document and Review Project Docs",
  "summary": "Create comprehensive project documentation for the current repository and review the resulting docs for accuracy, completeness, and clarity. Scope should stay documentation-focused and avoid code behavior changes unless required to verify or correct documented facts.",
  "goals": [
    "Document the project's purpose, architecture, setup, development workflow, testing workflow, key modules, and operational conventions.",
    "Ensure documentation reflects the current repository state rather than assumptions.",
    "Review the documentation for gaps, contradictions, stale information, and unclear instructions.",
    "Produce actionable review notes or apply documentation fixes if this later phase permits file edits."
  ],
  "non_goals": [
    "Changing application behavior or refactoring source code.",
    "Adding new dependencies or changing build/test configuration.",
    "Publishing documentation externally.",
    "Creating exhaustive per-symbol API reference unless the repository already has a documented convention for it."
  ],
  "acceptance_criteria": [
    {
      "id": "AC-1",
      "description": "Documentation covers project overview, setup, common commands, architecture/module map, development workflow, testing, and contribution or operational guidance."
    },
    {
      "id": "AC-2",
      "description": "Documented commands, paths, and module descriptions are verified against the repository's current files and configuration."
    },
    {
      "id": "AC-3",
      "description": "Existing docs are reviewed for stale, duplicated, conflicting, or missing content."
    },
    {
      "id": "AC-4",
      "description": "A review outcome is available that identifies documentation changes made or unresolved documentation gaps."
    },
    {
      "id": "AC-5",
      "description": "No source-code behavior changes are made as part of the documentation task."
    }
  ],
  "constraints": [
    "Keep scope documentation-only unless a later implementation phase explicitly authorizes code changes.",
    "Prefer repository evidence over assumptions when describing behavior.",
    "Keep documentation maintainable and aligned with existing doc structure and naming conventions.",
    "No test commands were supplied by CLI or config."
  ],
  "test_commands": [],
  "risk": "low",
  "open_questions": [
    "What specific documentation surfaces count as 'full documentation' for this project: README only, docs/ tree, architecture docs, CLI reference, ADRs, or all of these?",
    "Should the later implementation phase edit files directly or only produce a documentation review report?"
  ]
}
```

